import Image from "next/image";
import Link from "next/link";

interface ProjectCardProps {
  title: string;
  href: string;
  image?: string;
  description?: string;
}

export function ProjectCard({ title, href, image, description }: ProjectCardProps) {
  return (
    <Link
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      className="group not-prose block rounded-2xl bg-neutral-900 p-5 hover:bg-neutral-800 transition-colors duration-200 overflow-hidden"
    >
      <h3 className="text-lg font-bold text-neutral-100 group-hover:text-white mb-1">
        {title}
      </h3>
      {description && (
        <p className="text-neutral-400 text-sm mb-3">{description}</p>
      )}
      {image && (
        <div className="rounded-xl overflow-hidden border border-neutral-800 bg-white">
          <Image
            src={image}
            alt={`${title} screenshot`}
            width={600}
            height={400}
            className="w-full h-auto"
          />
        </div>
      )}
    </Link>
  );
}

export function ProjectGrid({ children }: { children: React.ReactNode }) {
  return (
    <div className="not-prose grid grid-cols-1 md:grid-cols-3 gap-4 items-start">
      {children}
    </div>
  );
}
